# Add the MongoDB Node.js Driver to your project
npm install mongodb
```

For detailed installation instructions, see the
[MongoDB Node Driver documentation](node).

The following index definition indexes the
`plot_embedding_voyage_3_large` field as the MongoDB Vector Search field when
querying the collection.

- Create a file named `vector-search-index.js`, and paste the following
  code into it:

  ```javascript
  const { MongoClient } = require("mongodb");

  // Connect to your MongoDB deployment
  const MONGODB_URI = "<connection-string>";
  const client = new MongoClient(MONGODB_URI);

  async function run() {
      try {
        const database = client.db("sample_mflix");
        const collection = database.collection("embedded_movies");

        // Define your vector search index
        const index = {
            name: "hybrid-vector-search",
            type: "vectorSearch",
            definition: {
              "fields": [
                {
                  "type": "vector",
                  "numDimensions": 2048,
                  "path": "plot_embedding_voyage_3_large",
                  "similarity": "dotProduct"
                }
              ]
            }
        }

        // Call the method to create the index
        const result = await collection.createSearchIndex(index);
        console.log(result);
      } finally {
        await client.close();
      }
  }
  run().catch(console.dir);

  ```

- Run the following command to execute the code:

  **Input:**

  ```javascript
  node vector-search-index.js
  ```

  **Output:**

  ```javascript
  hybrid-vector-search
  ```

  MongoDB Vector Search might take few minutes to create the index.

The following index definition automatically indexes all
dynamically indexable field types in the collection.

- Create a file named `text-search-index.js`, and paste the following
  code into it:

  ```javascript
  const { MongoClient } = require("mongodb");

  // Connect to your MongoDB deployment
  const MONGODB_URI = "<connection-string>";
  const client = new MongoClient(MONGODB_URI);

  async function run() {
      try {
        const database = client.db("sample_mflix");
        const collection = database.collection("embedded_movies");

        // Define your search index
        const index = {
            name: "hybrid-full-text-search",
            type: "search",
            definition: {
              "mappings": {
                "dynamic": true
              }
            }
        }

        // Call the method to create the index
        const result = await collection.createSearchIndex(index);
        console.log(result);
      } finally {
        await client.close();
      }
  }
  run().catch(console.dir);
  ```

- Run the following command to execute the code:

  **Input:**

  ```javascript
  node text-search-index.js
  ```

  **Output:**

  ```javascript
  hybrid-full-text-search
  ```

  MongoDB Search might take few minutes to create the index.

